        },
        'expected': {
            'max_value': 15,
            'selected_ids': ['a', 'b', 'c'],
            'rejected': []
        }
    })

    # Test 6: Empty input
    test_cases.append({
        'input': {'sessions': []},
        'expected': {
            'max_value': 0,
            'selected_ids': [],
            'rejected': []
        }
    })

    # Test 7: Missing fields
    test_cases.append({
        'input': {
            'sessions': [
                {'id': 'a', 'start': '2026-05-01T09:00:00', 'value': 5},
