            <label>标题 <span style="color:#ef4444;">*</span></label>
            <input type="text" id="taskTitle" required placeholder="任务标题" maxlength="60">

            <label>备注 (可选)</label>
            <textarea id="taskDesc" placeholder="添加描述…" rows="2"></textarea>

            <label>优先级</label>
            <select id="taskPriority">
                <option value="low">低</option>
                <option value="medium" selected>中</option>
                <option value="high">高</option>
            </select>

            <div class="modal-actions">
                <button type="button" class="btn-cancel" id="modalCancel">取消</button>
                <button type="submit" class="btn-confirm" id="modalConfirm">保存</button>
            </div>
        </form>
    </div>
</div>

<script>
    (function() {
        "use strict";

        // ---------- 数据层 ----------
        const STORAGE_KEY = 'kanban_tasks_light';
        // 任务结构: { id, title, desc, priority, status, createdAt }

        // 当前任务数组
        let tasks = [];

        // 当前编辑的临时id (编辑模式时使用)
        let editingId = null;

        // DOM 元素
        const todoList = document.getElementById('todoList');
        const progressList = document.getElementById('progressList');
        const doneList = document.getElementById('doneList');
        const todoCount = document.getElementById('todoCount');
        const progressCount = document.getElementById('progressCount');
        const doneCount = document.getElementById('doneCount');
        const searchInput = document.getElementById('searchInput');
        const filterPriority = document.getElementById('filterPriority');
        const addTaskBtn = document.getElementById('addTaskBtn');
        const modal = document.getElementById('taskModal');
        const modalTitle = document.getElementById('modalTitle');
        const taskTitle = document.getElementById('taskTitle');
        const taskDesc = document.getElementById('taskDesc');
        const taskPriority = document.getElementById('taskPriority');
        const modalCancel = document.getElementById('modalCancel');
        const modalConfirm = document.getElementById('modalConfirm');

        // ---------- 数据持久化 ----------
        function loadTasks() {
            const stored = localStorage.getItem(STORAGE_KEY);
            if (stored) {
                try {
                    tasks = JSON.parse(stored);
                } catch(e) {
                    tasks = [];
                }
            } else {
                // 初始示例
                tasks = [
                    { id: '1', title: '设计原型', desc: '使用Figma完成主界面', priority: 'high', status: 'todo', createdAt: Date.now() - 86400000 },
                    { id: '2', title: '编写API文档', desc: 'swagger 整理', priority: 'medium', status: 'progress', createdAt: Date.now() - 172800000 },
                    { id: '3', title: '首页布局', desc: '响应式栅格', priority: 'low', status: 'done', createdAt: Date.now() - 259200000 },
                ];
            }
        }

        function saveTasks() {
            localStorage.setItem(STORAGE_KEY, JSON.stringify(tasks));
        }

        // ---------- 工具函数 ----------
        function generateId() {
            return Date.now().toString(36) + Math.random().toString(36).slice(2, 6);
        }

        function formatTime(ts) {
            const d = new Date(ts);
            const month = String(d.getMonth()+1).padStart(2,'0');
            const day = String(d.getDate()).padStart(2,'0');
            const hours = String(d.getHours()).padStart(2,'0');
            const mins = String(d.getMinutes()).padStart(2,'0');
            return `${month}-${day} ${hours}:${mins}`;
        }

        // 获取筛选后的任务 (搜索 + 优先级)
        function getFilteredTasks(status) {
            const keyword = searchInput.value.trim().toLowerCase();
            const priorityFilter = filterPriority.value;

            return tasks.filter(t => {
                if (t.status !== status) return false;
                // 搜索匹配
                if (keyword) {
                    const inTitle = t.title.toLowerCase().includes(keyword);
                    const inDesc = (t.desc || '').toLowerCase().includes(keyword);
                    if (!inTitle && !inDesc) return false;
                }
                // 优先级筛选
                if (priorityFilter !== 'all' && t.priority !== priorityFilter) return false;
                return true;
            });
        }

        // 渲染全部列
        function renderBoard() {
            renderColumn('todo', todoList, todoCount);
            renderColumn('progress', progressList, progressCount);
            renderColumn('done', doneList, doneCount);
        }

        function renderColumn(status, container, countEl) {
            const filtered = getFilteredTasks(status);
            container.innerHTML = '';
            filtered.forEach(task => {
                const card = createCardElement(task);
                container.appendChild(card);
            });
            // 更新数量
            const totalByStatus = tasks.filter(t => t.status === status).length;
            countEl.textContent = totalByStatus;
        }

        // 创建卡片 DOM (带拖拽属性)
        function createCardElement(task) {
            const card = document.createElement('div');
            card.className = `task-card priority-${task.priority}`;
            card.setAttribute('draggable', 'true');
            card.dataset.taskId = task.id;

            // 标题
            const titleDiv = document.createElement('div');
            titleDiv.className = 'task-title';
            titleDiv.textContent = task.title;

            // 描述
            const descDiv = document.createElement('div');
            descDiv.className = 'task-desc';
            descDiv.textContent = task.desc || '无备注';

            // 元信息：优先级 + 创建时间
            const metaDiv = document.createElement('div');
            metaDiv.className = 'task-meta';
            const priorityTag = document.createElement('span');
            priorityTag.className = 'task-priority-tag';
            const priorityMap = { high: '🔴 高', medium: '🟡 中', low: '🟢 低' };
            priorityTag.textContent = priorityMap[task.priority] || task.priority;
            const timeSpan = document.createElement('span');
            timeSpan.textContent = `🕒 ${formatTime(task.createdAt)}`;
            metaDiv.appendChild(priorityTag);
            metaDiv.appendChild(timeSpan);

            // 操作按钮组
            const actions = document.createElement('div');
            actions.className = 'task-actions';

            // 左移 (无障碍移动)
            const moveLeftBtn = document.createElement('button');
            moveLeftBtn.textContent = '◀ 左移';
            moveLeftBtn.className = 'btn-move';
            moveLeftBtn.setAttribute('aria-label', '将任务向左移动');
            moveLeftBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                moveTask(task.id, 'left');
            });

            // 右移
            const moveRightBtn = document.createElement('button');
            moveRightBtn.textContent = '右移 ▶';
            moveRightBtn.className = 'btn-move';
            moveRightBtn.setAttribute('aria-label', '将任务向右移动');
            moveRightBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                moveTask(task.id, 'right');
            });

            // 编辑
            const editBtn = document.createElement('button');
            editBtn.textContent = '✎ 编辑';
            editBtn.className = 'btn-edit';
            editBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                openEditModal(task.id);
            });

            // 删除
            const deleteBtn = document.createElement('button');
            deleteBtn.textContent = '✕ 删除';
            deleteBtn.className = 'btn-delete';
            deleteBtn.addEventListener('click', (e) => {
                e.stopPropagation();
                if (confirm(`确定删除任务“${task.title}”?`)) {
                    deleteTask(task.id);
                }
            });

            actions.appendChild(moveLeftBtn);
            actions.appendChild(moveRightBtn);
            actions.appendChild(editBtn);
            actions.appendChild(deleteBtn);

            // 组装卡片
            card.appendChild(titleDiv);
            card.appendChild(descDiv);
            card.appendChild(metaDiv);
            card.appendChild(actions);

            // ---------- 拖拽事件 ----------
            card.addEventListener('dragstart', (e) => {
                e.dataTransfer.setData('text/plain', task.id);
                card.classList.add('dragging');
            });
            card.addEventListener('dragend', (e) => {
                card.classList.remove('dragging');
                // 移除所有 drag-over
                document.querySelectorAll('.card-list').forEach(el => el.classList.remove('drag-over'));
            });

            return card;
        }

        // 移动任务 (无障碍)
        function moveTask(taskId, direction) {
            const task = tasks.find(t => t.id === taskId);
            if (!task) return;
            const statusOrder = ['todo', 'progress', 'done'];
            const idx = statusOrder.indexOf(task.status);
            if (direction === 'left' && idx > 0) {
                task.status = statusOrder[idx - 1];
            } else if (direction === 'right' && idx < statusOrder.length - 1) {
                task.status = statusOrder[idx + 1];
            } else {
                return; // 边界不动
            }
            saveTasks();
            renderBoard();
        }

        // 删除任务
        function deleteTask(taskId) {
            tasks = tasks.filter(t => t.id !== taskId);
            saveTasks();
            renderBoard();
        }

        // ---------- 拖拽放置 (列) ----------
        function setupDragDrop() {
            const lists = [todoList, progressList, doneList];
            lists.forEach(list => {
                // 取消默认以允许放置
                list.addEventListener('dragover', (e) => {
                    e.preventDefault();
                    list.classList.add('drag-over');
                });
                list.addEventListener('dragleave', () => {
                    list.classList.remove('drag-over');
                });
                list.addEventListener('drop', (e) => {
                    e.preventDefault();
                    list.classList.remove('drag-over');
                    const taskId = e.dataTransfer.getData('text/plain');
                    if (!taskId) return;
                    const task = tasks.find(t => t.id === taskId);
                    if (!task) return;
                    const targetStatus = list.dataset.status;
                    if (targetStatus && task.status !== targetStatus) {
                        task.status = targetStatus;
                        saveTasks();
                        renderBoard();
                    }
                });
            });
        }

        // ---------- 模态框：新增 / 编辑 ----------
        function openNewModal() {
            editingId = null;
            modalTitle.textContent = '📌 新增任务';
            taskTitle.value = '';
            taskDesc.value = '';
            taskPriority.value = 'medium';
            modal.classList.add('active');
            taskTitle.focus();
        }

        function openEditModal(taskId) {
            const task = tasks.find(t => t.id === taskId);
            if (!task) return;
            editingId = task.id;
            modalTitle.textContent = '✏️ 编辑任务';
            taskTitle.value = task.title;
            taskDesc.value = task.desc || '';
            taskPriority.value = task.priority;
            modal.classList.add('active');
            taskTitle.focus();
        }

        function closeModal() {
            modal.classList.remove('active');
            editingId = null;
        }

        // 保存 新增/编辑
        function handleModalSave(e) {
            e.preventDefault();
            const title = taskTitle.value.trim();
            if (!title) {
                alert('标题不能为空');
                return;
            }
            const desc = taskDesc.value.trim();
            const priority = taskPriority.value;

            if (editingId) {
                // 编辑模式
                const task = tasks.find(t => t.id === editingId);
                if (task) {
                    task.title = title;
                    task.desc = desc;
                    task.priority = priority;
                }
            } else {
                // 新增
                const newTask = {
                    id: generateId(),
                    title: title,
                    desc: desc,
                    priority: priority,
                    status: 'todo',  // 默认待办
                    createdAt: Date.now(),
                };
                tasks.push(newTask);
            }
            saveTasks();
            renderBoard();
            closeModal();
        }

        // ---------- 搜索/筛选 监听 ----------
        function onFilterChange() {
            renderBoard();
        }

        // ---------- 初始化 ----------
        function init() {
            loadTasks();
            renderBoard();
            setupDragDrop();

            // 事件绑定
            addTaskBtn.addEventListener('click', openNewModal);
            modalCancel.addEventListener('click', closeModal);
            modalConfirm.addEventListener('click', handleModalSave);
            // 点击背景关闭
            modal.addEventListener('click', (e) => {
                if (e.target === modal) closeModal();
            });
            // 表单提交
            document.getElementById('modalForm').addEventListener('submit', handleModalSave);

            searchInput.addEventListener('input', onFilterChange);
            filterPriority.addEventListener('change', onFilterChange);
        }

        init();
    })();
</script>
</body>
</html>
